package ir.tahamohamadi.resume.api.admin;
import ir.tahamohamadi.common.api.PageResponse; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.http.*; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; import java.util.UUID;
@RestController @Validated @RequestMapping("/api/v1/admin/resume/entries") public class AdminResumeEntryController {private final AdminResumeEntryService service;public AdminResumeEntryController(AdminResumeEntryService service){this.service=service;}@GetMapping public PageResponse<AdminResumeEntryResponse> list(@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(100) int size,@RequestParam(defaultValue="sortOrder,asc") String sort){return PageResponse.from(service.list(page,size,sort));}@GetMapping("/{id}") public AdminResumeEntryResponse get(@PathVariable UUID id){return service.get(id);}@PostMapping public ResponseEntity<AdminResumeEntryResponse> create(@Valid @RequestBody AdminResumeEntryRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}@PutMapping("/{id}") public AdminResumeEntryResponse update(@PathVariable UUID id,@Valid @RequestBody AdminResumeEntryRequest r){return service.update(id,r);}@PostMapping("/{id}/publish") public AdminResumeEntryResponse publish(@PathVariable UUID id,@RequestParam long version){return service.publish(id,version);}@PostMapping("/{id}/archive") public AdminResumeEntryResponse archive(@PathVariable UUID id,@RequestParam long version){return service.archive(id,version);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id,@RequestParam long version){service.delete(id,version);}}
